class Solution:
    def sumCounts(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        bit1 = [0] * (n + 2)
        bit2 = [0] * (n + 2)

        def _update(i, v):
            x = i
            while x <= n:
                bit1[x] += v
                bit2[x] += v * (i - 1)
                x += x & (-x)

        def _range_update(l, r, v):
            if l > r:
                return
            _update(l, v)
            _update(r + 1, -v)

        def _prefix_query(i):
            if i <= 0:
                return 0
            s1 = 0
            x = i
            while x > 0:
                s1 += bit1[x]
                x -= x & (-x)
            s2 = 0
            x = i
            while x > 0:
                s2 += bit2[x]
                x -= x & (-x)
            return s1 * i - s2

        def _range_query(l, r):
            if l > r:
                return 0
            return _prefix_query(r) - _prefix_query(l - 1)

        last_occurrence = {}
        sq_total = 0
        answer = 0
        for r in range(1, n + 1):
            v = nums[r - 1]
            last1 = last_occurrence.get(v, 0)
            l = last1 + 1
            before = _range_query(l, r)
            count = r - l + 1
            delta = 2 * before + count
            sq_total = (sq_total + delta) % MOD
            _range_update(l, r, 1)
            last_occurrence[v] = r
            answer = (answer + sq_total) % MOD
        return answer % MOD

