var sumCounts = function(nums) {
    const MOD = 1000000007n;
    const n = nums.length;
    const bit1 = new Array(n + 2).fill(0n);
    const bit2 = new Array(n + 2).fill(0n);

    function update(i, v) {
        let x = i;
        while (x <= n) {
            bit1[x] += v;
            bit2[x] += v * BigInt(i - 1);
            x += x & (-x);
        }
    }

    function rangeUpdate(l, r, v) {
        if (l > r) return;
        update(l, v);
        update(r + 1, -v);
    }

    function prefixQuery(i) {
        if (i <= 0) return 0n;
        let s1 = 0n;
        let x = i;
        while (x > 0) {
            s1 += bit1[x];
            x -= x & (-x);
        }
        let s2 = 0n;
        x = i;
        while (x > 0) {
            s2 += bit2[x];
            x -= x & (-x);
        }
        return s1 * BigInt(i) - s2;
    }

    function rangeQuery(l, r) {
        if (l > r) return 0n;
        return prefixQuery(r) - prefixQuery(l - 1);
    }

    const lastOccurrence = new Map();
    let sqTotal = 0n;
    let answer = 0n;
    for (let r = 1; r <= n; r++) {
        const v = nums[r - 1];
        const last1 = lastOccurrence.get(v) || 0;
        const l = last1 + 1;
        const before = rangeQuery(l, r);
        const count = BigInt(r - l + 1);
        const delta = 2n * before + count;
        sqTotal = (sqTotal + delta) % MOD;
        rangeUpdate(l, r, 1n);
        lastOccurrence.set(v, r);
        answer = (answer + sqTotal) % MOD;
    }
    return Number(((answer % MOD) + MOD) % MOD);
};
